+/* ===========================
+   RESET
+   =========================== */
+
+* {
+  box-sizing: border-box;
+  margin: 0;
+  padding: 0;
+}
+
+/* ===========================
+   THEME VARIABLES (Dracula)
+   =========================== */
+
+:root {
+  font-family: Inter, system-ui, Avenir, Helvetica, Arial, sans-serif;
+  line-height: 1.6;
+  font-weight: 400;
+
+  font-synthesis: none;
+  text-rendering: optimizeLegibility;
+  -webkit-font-smoothing: antialiased;
+  -moz-osx-font-smoothing: grayscale;
+
+  /* Dracula palette */
+  --bg: #282a36;
+  --bg-alt: #44475a;
+  --bg-deep: #1f2029;
+
+  --fg: #f8f8f2;
+  --fg-muted: #b0b3c6;
+  --comment: #6272a4;
+
+  --cyan: #8be9fd;
+  --green: #50fa7b;
+  --orange: #ffb86c;
+  --pink: #ff79c6;
+  --purple: #bd93f9;
+  --red: #ff5555;
+  --yellow: #f1fa8c;
+
+  color-scheme: dark;
+  color: var(--fg);
+  background-color: var(--bg);
+}
+
+/* ===========================
+   BASE
+   =========================== */
+
+body {
+  min-width: 320px;
+  min-height: 100vh;
+  background: var(--bg);
+  color: var(--fg);
+}
+
+/* ===========================
+   LINKS
+   =========================== */
+
+a {
+  color: var(--purple);
+  text-decoration: none;
+}
+
+a:hover {
+  color: var(--pink);
+}
+
+/* ===========================
+   NAVBAR
+   =========================== */
+
+.navbar {
+  display: flex;
+  justify-content: space-between;
+  align-items: center;
+  padding: 1.2rem 2rem;
+  background: var(--bg-deep);
+  border-bottom: 1px solid var(--bg-alt);
+}
+
+.navbar a {
+  color: var(--fg);
+  margin-left: 1.5rem;
+  opacity: 0.85;
+}
+
+.navbar a:hover {
+  color: var(--cyan);
+  opacity: 1;
+}
+
+.logo {
+  font-weight: 700;
+  font-size: 1.2rem;
+  color: var(--green);
+}
+
+/* ===========================
+   HERO
+   =========================== */
+
+.hero {
+  padding: 6rem 2rem;
+  text-align: center;
+}
+
+.hero h1 {
+  font-size: 3rem;
+  color: var(--fg);
+}
+
+.hero p {
+  max-width: 600px;
+  margin: 1rem auto 2rem;
+  color: var(--fg-muted);
+}
+
+/* ===========================
+   BUTTONS
+   =========================== */
+
+.btn {
+  padding: 0.7rem 1.2rem;
+  border-radius: 6px;
+  border: 1px solid var(--purple);
+  background: transparent;
+  color: var(--fg);
+  font-weight: 500;
+  cursor: pointer;
+  transition: background 0.2s ease, transform 0.1s ease;
+}
+
+.btn.primary {
+  background: var(--purple);
+  color: var(--bg);
+}
+
+.btn.secondary {
+  border-color: var(--comment);
+}
+
+.btn:hover {
+  background: var(--cyan);
+  color: var(--bg);
+}
+
+.btn:active {
+  transform: translateY(1px);
+}
+
+/* ===========================
+   FEATURES
+   =========================== */
+
+.features {
+  padding: 4rem 2rem;
+}
+
+.feature-grid {
+  display: grid;
+  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
+  gap: 2rem;
+  margin-top: 2rem;
+}
+
+.feature {
+  background: var(--bg-alt);
+  padding: 1.5rem;
+  border-radius: 10px;
+  border: 1px solid var(--comment);
+}
+
+/* ===========================
+   SECTIONS
+   =========================== */
+
+.api,
+.architecture,
+.cta {
+  padding: 4rem 2rem;
+  text-align: center;
+}
+
+/* ===========================
+   CODE BLOCK
+   =========================== */
+
+.code {
+  background: var(--bg-deep);
+  padding: 1.5rem;
+  border-radius: 8px;
+  text-align: left;
+  max-width: 700px;
+  margin: 2rem auto 0;
+  font-family: ui-monospace, SFMono-Regular, Menlo, monospace;
+  color: var(--yellow);
+}
+
+/* ===========================
+   FOOTER
+   =========================== */
+
+.footer {
+  text-align: center;
+  padding: 2rem;
+  font-size: 0.9rem;
+  color: var(--fg-muted);
+  opacity: 0.8;
+}
+
+/* ===========================
+   UTILITIES
+   =========================== */
+
+.error {
+  color: var(--red);
+}
+
+.muted {
+  color: var(--comment);
+}
+
+/* ===========================
+   ITEMS TABLE (Dracula theme)
+   =========================== */
+
+.bp-items-root {
+  margin-top: 2rem;
+}
+
+/* Title */
+.bp-items-root h1 {
+  margin-bottom: 1rem;
+  font-size: 1.6rem;
+  color: var(--green);
+}
+
+/* Table layout */
+.bp-items-root table {
+  width: 100%;
+  border-collapse: collapse;
+  table-layout: fixed;
+  background: var(--bg-alt);
+  border-radius: 10px;
+  overflow: hidden;
+}
+
+/* Header */
+.bp-items-root thead {
+  background: var(--bg-deep);
+}
+
+.bp-items-root th {
+  padding: 12px 14px;
+  text-align: left;
+  font-size: 0.85rem;
+  font-weight: 600;
+  color: var(--purple);
+  border-bottom: 1px solid var(--comment);
+}
+
+/* Cells */
+.bp-items-root td {
+  padding: 12px 14px;
+  vertical-align: top;
+  border-bottom: 1px solid var(--comment);
+  color: var(--fg);
+  word-wrap: break-word;
+}
+
+/* Zebra rows */
+.bp-items-root tbody tr:nth-child(even) {
+  background: rgba(255, 255, 255, 0.03);
+}
+
+/* Row hover */
+.bp-items-root tbody tr:hover {
+  background: rgba(139, 233, 253, 0.08);
+}
+
+/* ===========================
+   COLLAPSIBLE CELLS
+   =========================== */
+
+.bp-items-root .collapsible {
+  max-height: 2.8em;
+  overflow: hidden;
+  cursor: pointer;
+  position: relative;
+  padding-right: 18px;
+  transition: max-height 0.25s ease;
+}
+
+/* Arrow */
+.bp-items-root .collapsible::after {
+  content: '▼';
+  position: absolute;
+  right: 4px;
+  bottom: 2px;
+  font-size: 0.7rem;
+  color: var(--comment);
+}
+
+/* Expanded */
+.bp-items-root .collapsible.expanded {
+  max-height: 100vh;
+}
+
+.bp-items-root .collapsible.expanded::after {
+  content: '▲';
+}
+
+/* ===========================
+   EMPTY + ERROR STATES
+   =========================== */
+
+.bp-items-root .error {
+  color: var(--red);
+  margin-bottom: 1rem;
+  font-weight: 500;
+}
+
+.bp-items-root p {
+  color: var(--fg-muted);
+}
+
+/* ===========================
+   LEGACY
+   =========================== */
+
+#root {
+  margin: 0 auto;
+  text-align: center;
+}
+
+.logo {
+  height: 6em;
+  padding: 1.5em;
+  will-change: filter;
+  transition: filter 300ms;
+}
+.logo:hover {
+  filter: drop-shadow(0 0 2em #646cffaa);
+}
+.logo.react:hover {
+  filter: drop-shadow(0 0 2em #61dafbaa);
+}
+
+@keyframes logo-spin {
+  from {
+    transform: rotate(0deg);
+  }
+  to {
+    transform: rotate(360deg);
+  }
+}
+
+@media (prefers-reduced-motion: no-preference) {
+  a:nth-of-type(2) .logo {
+    animation: logo-spin infinite 20s linear;
+  }
+}
+
+.card {
+  padding: 2em;
+}
+
+.read-the-docs {
+  color: #888;
+}
+
+.nav-right {
+  color: var(--fg);
+  margin-left: 1.5rem;
+  opacity: 0.85;
+}
+
+.addr-wrap {
+  display: inline-flex;
+  align-items: center;
+  gap: 6px;
+}
+
+.addr-copy {
+  cursor: pointer;
+  opacity: 0.7;
+  font-size: 0.9em;
+}
+
+.addr-copy:hover {
+  opacity: 1;
+}
+.nav-right {
+  margin-left: auto; /* pushes it to the right */
+  display: flex;
+  align-items: center;
+}
