+   ======================= */
+
+.btn.neon {
+  --neon-color: #8be9fd;
+  --neon-glow: rgba(139, 233, 253, 0.6);
+
+  padding: 0.8rem 1.6rem;
+  font-size: 1rem;
+  font-weight: 600;
+  color: var(--bg);
+  background: var(--neon-color);
+  border: 2px solid var(--neon-color);
+  border-radius: 8px;
+  text-transform: uppercase;
+  letter-spacing: 1.2px;
+  cursor: pointer;
+  position: relative;
+  transition: transform 0.1s ease-in-out;
+  box-shadow:
+    0 0 8px var(--neon-color),
+    0 0 16px var(--neon-glow),
+    0 0 24px var(--neon-glow),
+    0 0 32px var(--neon-glow);
+  animation: neon-pulse 1.8s infinite alternate ease-in-out;
+}
+
+@keyframes neon-pulse {
+  from {
+    box-shadow:
+      0 0 6px var(--neon-color),
+      0 0 12px var(--neon-glow),
+      0 0 18px var(--neon-glow),
+      0 0 24px var(--neon-glow);
+  }
+  to {
+    box-shadow:
+      0 0 12px var(--neon-color),
+      0 0 24px var(--neon-glow),
+      0 0 36px var(--neon-glow),
+      0 0 48px var(--neon-glow);
+  }
+}
+
+/* magnetic press effect */
+.btn.neon:active,
+.btn.neon.clicked {
+  animation: none;
+  transform: scale(0.95);
+  box-shadow:
+    0 0 4px var(--neon-color),
+    0 0 8px var(--neon-glow);
+  transition: transform 0.05s ease-in-out;
+}
